import React, { useState, useEffect } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';
import axios from 'axios';

const Calendar = () => {
  const [events, setEvents] = useState([]); // Use state to store events

  // Fetch events from the backend
  useEffect(() => {
    axios
      .get('http://localhost:3001/events')  // Ensure the correct URL
      .then(response => {
        setEvents(response.data); // Set the events data into state
      })
      .catch(error => {
        console.error('Error fetching events:', error);
      });
  }, []);

  // FullCalendar setup
  return (
    <div>
      <FullCalendar
        plugins={[dayGridPlugin, interactionPlugin]}
        initialView="dayGridMonth"
        events={events}  // Use the state that stores events
        eventClick={(info) => {
          info.jsEvent.preventDefault();
          if (info.event.url) {
            window.open(info.event.url);
          }
        }}
      />
    </div>
  );
};

export default Calendar;
